import { MatCardModule } from '@angular/material/card';
import { MatDialog } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { CustomerService } from '../../core/services/customer.service';
import { Customer } from '../../core/models/customer.model';
import { CustomerFormDialogComponent } from './customer-form-dialog/customer-form-dialog.component';
import { ConfirmDialogComponent } from '../../shared/components/confirm-dialog/confirm-dialog.component';

@Component({
  selector: 'app-customers',
  standalone: true,
  imports: [
    CommonModule, RouterLink,
    MatTableModule, MatInputModule, MatFormFieldModule,
    MatButtonModule, MatIconModule, MatTooltipModule,
    MatProgressSpinnerModule, MatCardModule,
  ],
  templateUrl: './customers.component.html',
})
export class CustomersComponent implements OnInit {
  @ViewChild(MatPaginator) set paginator(p: MatPaginator) {
    if (p) {
      this.dataSource.paginator = p;
    }
  }

  displayedColumns = ['id', 'name', 'identification', 'email', 'birthDate', 'age', 'actions'];
  dataSource = new MatTableDataSource<Customer>([]);
  loading = true;
  error = '';

  constructor(
    private customerService: CustomerService,
    private dialog: MatDialog,
    private snackBar: MatSnackBar
  ) {}

  ngOnInit(): void {
    this.loadCustomers();
  }

  loadCustomers(): void {
    this.loading = true;
    this.error = '';
    this.customerService.getAll().subscribe({
      next: (customers) => {
        this.dataSource.data = customers;
        this.loading = false;
      },
      error: (err: Error) => {
        this.error = err.message;
        this.loading = false;
      },
    });
  }

  openCreate(): void {
    const ref = this.dialog.open(CustomerFormDialogComponent, {
      data: {},
      width: '540px',
    });
    ref.afterClosed().subscribe(result => {
      if (result) this.loadCustomers();
    });
  }

  openEdit(customer: Customer): void {
    const ref = this.dialog.open(CustomerFormDialogComponent, {
      data: { customer },
      width: '540px',
    });
    ref.afterClosed().subscribe(result => {
      if (result) this.loadCustomers();
    });
  }

  confirmDelete(customer: Customer): void {
    const ref = this.dialog.open(ConfirmDialogComponent, {
      data: {
        title: 'Eliminar cliente',
        message: `¿Está seguro de eliminar a <strong>${customer.firstName} ${customer.lastName}</strong>?<br>
          Esta acción no se puede deshacer. El cliente no puede tener cuentas activas.`,
        confirmLabel: 'Eliminar',
        cancelLabel: 'Cancelar',
      },
      width: '400px',
    });
    ref.afterClosed().subscribe(confirmed => {
      if (!confirmed) return;
      this.customerService.delete(customer.id).subscribe({
        next: () => {
          this.snackBar.open('Cliente eliminado exitosamente', 'Cerrar', { duration: 3000 });
          this.loadCustomers();
        },
        error: (err: Error) => {
          this.snackBar.open(err.message, 'Cerrar', { duration: 5000, panelClass: 'snack-error' });
        },
      });
    });
  }

  calcAge(birthDate: string): number {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  }

  formatDate(dateStr?: string): string {
    if (!dateStr) return '-';
    return new Date(dateStr).toLocaleDateString('es-CO', {
      day: '2-digit', month: 'short', year: 'numeric',
    });
  }

  get totalCustomers(): number {
    return this.dataSource.data.length;
  }

  idTypeLabels: { [key: string]: string | undefined } = {
    CC: 'CC', CE: 'CE', TI: 'TI', PASSPORT: 'Pasaporte', NIT: 'NIT',
  };
}
<div class="page-container">

  <!-- Header -->
  <div class="page-header">
    <div class="header-left">
      <div class="header-icon">
        <mat-icon>people</mat-icon>
      </div>
      <div>
        <h1>Clientes</h1>
        <p class="subtitle">
          @if (!loading) { {{ totalCustomers }} cliente{{ totalCustomers !== 1 ? 's' : '' }} registrado{{ totalCustomers !== 1 ? 's' : '' }} }
          @else { Cargando... }
        </p>
      </div>
    </div>
    <button mat-flat-button color="primary" (click)="openCreate()">
      <mat-icon>add</mat-icon>
      Nuevo cliente
    </button>
  </div>

  <!-- Card con tabla -->
  <mat-card>

    <!-- Loading -->
    @if (loading) {
      <mat-card-content class="loading-state" style="padding:24px 16px;">
        <mat-spinner diameter="20"></mat-spinner>
        <span>Cargando clientes...</span>
      </mat-card-content>
    }

    <!-- Error -->
    @if (error) {
      <mat-card-content style="padding:16px;">
        <div class="error-state">
          <mat-icon>error_outline</mat-icon>
          Error cargando clientes. Verifique que el servidor esté activo.
        </div>
      </mat-card-content>
    }

    <!-- Tabla -->
    @if (!loading && !error) {
      <div class="table-wrap">
        <table mat-table [dataSource]="dataSource">

          <!-- ID -->
          <ng-container matColumnDef="id">
            <th mat-header-cell *matHeaderCellDef class="col-id">ID</th>
            <td mat-cell *matCellDef="let c" class="col-id id-cell">{{ c.id }}</td>
          </ng-container>

          <!-- Nombre -->
          <ng-container matColumnDef="name">
            <th mat-header-cell *matHeaderCellDef>Nombre</th>
            <td mat-cell *matCellDef="let c">
              <span class="name-cell">{{ c.firstName }} {{ c.lastName }}</span>
            </td>
          </ng-container>

          <!-- Identificación -->
          <ng-container matColumnDef="identification">
            <th mat-header-cell *matHeaderCellDef>Identificación</th>
            <td mat-cell *matCellDef="let c">
              <div class="id-badge">
                <span class="type-chip">{{ idTypeLabels[c.identificationType] ?? c.identificationType }}</span>
                <span class="number">{{ c.identificationNumber }}</span>
              </div>
            </td>
          </ng-container>

          <!-- Correo -->
          <ng-container matColumnDef="email">
            <th mat-header-cell *matHeaderCellDef>Correo</th>
            <td mat-cell *matCellDef="let c" class="email-cell">{{ c.email }}</td>
          </ng-container>

          <!-- Nacimiento -->
          <ng-container matColumnDef="birthDate">
            <th mat-header-cell *matHeaderCellDef>Nacimiento</th>
            <td mat-cell *matCellDef="let c">{{ formatDate(c.birthDate) }}</td>
          </ng-container>

          <!-- Edad -->
          <ng-container matColumnDef="age">
            <th mat-header-cell *matHeaderCellDef class="col-center">Edad</th>
            <td mat-cell *matCellDef="let c" class="col-center">
              <span class="age-badge">{{ c.age ?? calcAge(c.birthDate) }} años</span>
            </td>
          </ng-container>

          <!-- Acciones -->
          <ng-container matColumnDef="actions">
            <th mat-header-cell *matHeaderCellDef class="col-actions">Acciones</th>
            <td mat-cell *matCellDef="let c" class="col-actions">
              <div class="actions-group">
                <button mat-icon-button class="action-btn view-btn"
                        [routerLink]="['/customers', c.id]" matTooltip="Ver detalle">
                  <mat-icon>visibility</mat-icon>
                </button>
                <button mat-icon-button class="action-btn edit-btn"
                        (click)="openEdit(c)" matTooltip="Editar">
                  <mat-icon>edit</mat-icon>
                </button>
                <button mat-icon-button class="action-btn delete-btn"
                        (click)="confirmDelete(c)" matTooltip="Eliminar">
                  <mat-icon>delete</mat-icon>
                </button>
              </div>
            </td>
          </ng-container>

          <tr mat-header-row *matHeaderRowDef="displayedColumns"></tr>
          <tr mat-row *matRowDef="let row; columns: displayedColumns;"></tr>

          <!-- Sin resultados -->
          <tr class="mat-row" *matNoDataRow>
            <td class="mat-cell" [attr.colspan]="displayedColumns.length">
              <div class="empty-state">
                <mat-icon>people_outline</mat-icon>
                <p>No hay clientes registrados</p>
                <button mat-stroked-button color="primary" (click)="openCreate()">
                  <mat-icon>add</mat-icon> Crear primer cliente
                </button>
              </div>
            </td>
          </tr>
        </table>
      </div>

    }
  </mat-card>

</div>
